const conv = $('Find Conversation').first().json;
const history = $input.all().map(i => i.json);
const clientName = $env.CLIENT_NAME || 'il nostro team';

const chatMessages = history.map(m => ({
  role: m.direction === 'outbound' ? 'assistant' : 'user',
  content: m.body
}));

const systemPrompt = `Sei un assistente di qualificazione commerciale per ${clientName}.\nIl lead si chiama ${conv.first_name} ${conv.last_name} e si occupa di: ${conv.business_desc}.\nConduci la conversazione in italiano, in modo naturale e professionale.\n\nFai queste domande in sequenza (una alla volta, senza ripetere domande già poste):\n1. Qual è la sfida principale che stai cercando di risolvere?\n2. Hai già un budget allocato per questo tipo di soluzione?\n3. In che arco di tempo vorresti vedere dei risultati?\n4. Sei tu la persona che prende le decisioni su questo investimento?\n\nDopo aver raccolto le risposte a tutte le domande, assegna un punteggio da 0 a 10.\n\nRispondi SEMPRE e SOLO con JSON valido, senza markdown:\n{\"message\": \"testo da inviare\", \"score\": null, \"is_final\": false}\n\nQuando hai tutte le informazioni:\n{\"message\": \"messaggio finale senza link calendly\", \"score\": 8, \"is_final\": true}`;

const requestBody = JSON.stringify({
  model: 'gpt-4o',
  messages: [{ role: 'system', content: systemPrompt }, ...chatMessages],
  response_format: { type: 'json_object' },
  temperature: 0.7
});

return [{ json: {
  requestBody,
  conversation_id: conv.id,
  phone: $('Twilio Webhook').first().json.body.From
} }];

const raw = $input.first().json.choices[0].message.content;
let parsed;
try { parsed = JSON.parse(raw); } catch(e) {
  const m = raw.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : { message: raw, score: null, is_final: false };
}
const prev = $('Build GPT Prompt').first().json;
return [{ json: { ...parsed, conversation_id: prev.conversation_id, phone: prev.phone } }];

const d = $input.first().json;
const score = d.score;
let outcome, finalMessage;
if (score >= 7) {
  outcome = 'zoom_call';
  finalMessage = `${d.message}\n\n📅 Prenota la tua call Zoom qui: ${$env.CALENDLY_ZOOM_LINK}`;
} else if (score >= 4) {
  outcome = 'voice_call';
  finalMessage = `${d.message}\n\n📞 Prenota la tua chiamata qui: ${$env.CALENDLY_VOICE_LINK}`;
} else {
  outcome = 'not_qualified';
  finalMessage = d.message;
}
return [{ json: { ...d, outcome, finalMessage } }];
